# Cache decorator with TTL
def cache_with_ttl(ttl=300, key_prefix=''):
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            # Generate cache key based on function name and arguments
            cache_key_data = f"{key_prefix}:{f.__name__}:{str(args)}:{str(sorted(kwargs.items()))}"
            cache_key = hashlib.sha256(cache_key_data.encode()).hexdigest()
            
            try:
                # Try to get from cache
                cached_result = cache_client.get(cache_key)
                if cached_result is not None:
                    app.logger.info(f"Cache HIT for key: {cache_key[:16]}...")
                    return cached_result
                
                app.logger.info(f"Cache MISS for key: {cache_key[:16]}...")
                
                # Execute function and cache result
                result = f(*args, **kwargs)
                cache_client.set(cache_key, result, expire=ttl)
                
                return result
            except Exception as e:
                app.logger.error(f"Cache error: {str(e)}")
                # Fallback to executing function without cache
                return f(*args, **kwargs)
        
        return decorated_function
    return decorator

